const source = $input.first().json;
let audit = source.output ?? source;

if (typeof audit === 'string') {
  const cleaned = audit.replace(/^```jsons*/i, '').replace(/^```s*/i, '').replace(/```$/i, '').trim();
  try {
    audit = JSON.parse(cleaned);
  } catch (error) {
    audit = {
      items: [],
      low_stock_items: [],
      invalid_rows: [{ reason: 'Agent output was not valid JSON', raw_output: audit }],
      risk_level: 'critical',
      reorder_plan: [],
      warehouse_recipient: 'warehouse',
      supplier_recipient: 'supplier',
      warehouse_message_draft: '',
      supplier_message_draft: '',
      approval_required: false,
      alert_required: false,
      reasoning_summary: 'Agent output could not be parsed.',
      actions_taken: ['log_check_failed'],
      run_source: 'unknown'
    };
  }
}

return [{
  json: {
    items: Array.isArray(audit.items) ? audit.items : [],
    low_stock_items: Array.isArray(audit.low_stock_items) ? audit.low_stock_items : [],
    invalid_rows: Array.isArray(audit.invalid_rows) ? audit.invalid_rows : [],
    risk_level: String(audit.risk_level || 'none').toLowerCase(),
    reorder_plan: Array.isArray(audit.reorder_plan) ? audit.reorder_plan : [],
    warehouse_recipient: audit.warehouse_recipient || 'warehouse',
    supplier_recipient: audit.supplier_recipient || 'supplier',
    warehouse_message_draft: audit.warehouse_message_draft || '',
    supplier_message_draft: audit.supplier_message_draft || '',
    approval_required: Boolean(audit.approval_required),
    alert_required: Boolean(audit.alert_required),
    reasoning_summary: audit.reasoning_summary || '',
    actions_taken: Array.isArray(audit.actions_taken) ? audit.actions_taken : [],
    run_source: audit.run_source || 'unknown'
  }
}];

const audit = $input.first().json;
const errors = [];
const allowedRisk = new Set(['none', 'low', 'medium', 'high', 'critical']);
const lowCount = Array.isArray(audit.low_stock_items) ? audit.low_stock_items.length : 0;
const plan = Array.isArray(audit.reorder_plan) ? audit.reorder_plan : [];

if (!allowedRisk.has(audit.risk_level)) errors.push('risk_level must be one of none, low, medium, high, critical');
if (audit.warehouse_recipient !== 'warehouse') errors.push('warehouse_recipient must be warehouse');
if (audit.supplier_recipient !== 'supplier') errors.push('supplier_recipient must be supplier');
if (Boolean(audit.alert_required) !== (lowCount > 0)) errors.push('alert_required must match low_stock_items count');
if (plan.length !== lowCount) errors.push('reorder_plan must contain one entry per low_stock_item');

for (const entry of plan) {
  if (!entry.item_name) errors.push('each reorder_plan entry needs item_name');
  const current = Number(entry.current_kg);
  const target = Number(entry.target_kg);
  const reorder = Number(entry.reorder_kg);
  if (!Number.isFinite(current) || current < 0) errors.push('current_kg must be a non-negative number');
  if (target !== 50) errors.push('target_kg must be 50');
  if (!Number.isFinite(reorder) || reorder <= 0) errors.push('reorder_kg must be a positive number');
  if (Number.isFinite(current) && Number.isFinite(reorder) && Math.abs((50 - current) - reorder) > 0.01) {
    errors.push('reorder_kg must equal 50 - current_kg');
  }
}

if (lowCount >= 3 && audit.approval_required !== true) errors.push('approval_required must be true for 3+ low items');
if (lowCount < 3 && audit.approval_required === true) errors.push('approval_required must be false for fewer than 3 low items');
if (audit.approval_required && String(audit.supplier_message_draft || '').trim() === '') errors.push('supplier_message_draft is required when approval is required');
if (lowCount > 0 && String(audit.warehouse_message_draft || '').trim() === '') errors.push('warehouse_message_draft is required when alert is required');

const isValidPlan = errors.length === 0;
return [{
  json: {
    ...audit,
    low_items_count: lowCount,
    is_valid_plan: isValidPlan,
    validation_errors: errors,
    should_notify_warehouse: isValidPlan && lowCount > 0,
    should_request_supplier_approval: isValidPlan && audit.approval_required === true && lowCount >= 3,
    execution_status: {
      warehouse_status: 'not_sent',
      supplier_approval_status: audit.approval_required ? 'not_requested' : 'not_required',
      supplier_email_status: 'not_sent'
    }
  }
}];

